import { useState, useEffect } from "react";

function HargaTelurModal({ isOpen, onClose, onSave, editData, darkMode }) {
  const [formData, setFormData] = useState({
    jenisTelur: "",
    satuan: "Butir",
    harga: "",
    berlakuSejak: "",
    keterangan: "",
