              type="date"
              name="tanggal"
              value={formData.tanggal}
              onChange={handleChange}
              className={inputClass}
              required
            />
          </div>

          {/* Kandang */}
          <div>
            <label className={labelClass}>Kandang</label>
            <select
              name="kandang"
              value={formData.kandang}
              onChange={handleChange}
              className={inputClass}
